const b = $input.first().json.body || {};
const raw = String(b.siteName || '').toLowerCase().trim();
if (!/^[a-z0-9][a-z0-9-]{1,40}$/.test(raw)) {
  throw new Error('invalid siteName: must match ^[a-z0-9][a-z0-9-]{1,40}$ (got "' + raw + '")');
}
const RESERVED = ['studio','canvas','coolify','www','api','automate','aita','mail','smtp','admin','app','dev','staging','test','ns1','ns2'];
if (RESERVED.includes(raw)) {
  throw new Error('reserved subdomain: ' + raw);
}
const domain = String(b.domain || 'aihe.me');
const cfZones = {
  'aihe.dev': 'c8b83f69a20a8092169e1c38fb2622b2',
  'aihe.me': '978747aba768e3a3b8ab16cf0d808311',
};
if (!cfZones[domain]) throw new Error('invalid domain: ' + domain + ' (use aihe.dev or aihe.me)');
const hex = (n) => Array.from({length: n}, () => Math.floor(Math.random() * 16).toString(16)).join('');
return [{ json: {
  siteName: raw,
  domain,
  cfZoneId: cfZones[domain],
  appName: 'plasmic-' + raw,
  dnsName: raw + '.' + domain,
  fqdn: 'https://' + raw + '.' + domain,
  text: String(b.text || ('Welcome to ' + raw)),
  revalidateSecret: hex(48),
} }];

const ctx = $('Validate Input').first().json;
const dnsRes = $('Check Existing DNS').first().json;
const dnsRecords = (dnsRes && dnsRes.result) || [];
// the HTTP node splits Coolify's JSON-array response into one item per app,
// so collect ALL items — .first().json is just the first application object
let apps = [];
try { apps = $('Check Existing App').all().map(i => i.json); } catch (e) {}
if (apps.length === 1) {
  const j = apps[0];
  if (Array.isArray(j)) apps = j;
  else if (Array.isArray(j.data)) apps = j.data;
}
const named = apps.filter(a => a && a.name === ctx.appName);
// duplicate names can exist (e.g. an interrupted run); prefer the app that owns our fqdn
const existing = named.find(a => String(a.fqdn || a.domains || '').includes(ctx.dnsName)) || named[0] || null;
return [{ json: {
  ...ctx,
  dnsExists: dnsRecords.length > 0,
  existingDnsId: dnsRecords.length > 0 ? dnsRecords[0].id : null,
  appExists: !!existing,
  appUuid: existing ? existing.uuid : null,
} }];

const ctx = $('Assess State').first().json;
// the HTTP node splits the envs array into one item per env var
let envs = $input.all().map(i => i.json);
if (envs.length === 1) {
  const j = envs[0];
  if (Array.isArray(j)) envs = j;
  else if (Array.isArray(j.data)) envs = j.data;
}
const pid = envs.find(e => e && e.key === 'PLASMIC_PROJECT_ID');
return [{ json: { ...ctx, projectId: pid ? pid.value : null, reused: true } }];

const ctx = $('Assess State').first().json;
let appUuid = ctx.appUuid, projectId = null, reused = false;
try { projectId = $('Extract Existing Project').first().json.projectId; reused = true; } catch (e) {}
if (!reused) {
  appUuid = $('Create Coolify App').first().json.uuid;
  projectId = $('Create Plasmic Project').first().json.projectId;
}
if (!appUuid) throw new Error('resolve-context: no app uuid');
return [{ json: { appUuid, projectId, reused, url: ctx.fqdn, dnsName: ctx.dnsName } }];

const d = $input.first().json;
const deploymentUuid = d && d.deployments && d.deployments[0] ? d.deployments[0].deployment_uuid : null;
if (!deploymentUuid) throw new Error('deploy trigger returned no deployment_uuid: ' + JSON.stringify(d).slice(0, 200));
return [{ json: { deploymentUuid } }];

const status = String($input.first().json.status || 'unknown');
if (['failed', 'cancelled', 'cancelled-by-user'].includes(status)) {
  throw new Error('deployment failed with status: ' + status);
}
if ($runIndex > 40) throw new Error('deployment timeout after ~10 min (last status: ' + status + ')');
return [{ json: { done: status === 'finished' } }];

const code = Number($input.first().json.statusCode || 0);
if ($runIndex > 20 && code !== 200) {
  throw new Error('site not live after ~3.5 min: last HTTP status ' + code);
}
return [{ json: { ok: code === 200 } }];

const err = $input.first().json;
const stage = (typeof $prevNode !== 'undefined' && $prevNode.name) ? $prevNode.name : 'unknown';
const causeRaw = err && err.error;
const cause = (typeof causeRaw === 'string' && causeRaw)
  || (causeRaw && (causeRaw.message || causeRaw.description))
  || (err && err.message)
  || JSON.stringify(err).slice(0, 300);
const diag = {};
function grab(node, pick) {
  const attempts = [
    ['first()', () => pick($(node).first().json)],
    ['first(0,0)', () => pick($(node).first(0, 0).json)],
    ['all()', () => { const a = $(node).all(); return a.length ? pick(a[0].json) : null; }],
  ];
  for (const [label, fn] of attempts) {
    try { const v = fn(); diag[node] = label; return v === undefined ? null : v; }
    catch (e) { diag[node] = (diag[node] || '') + label + ':' + String(e.message).slice(0, 80) + '; '; }
  }
  return null;
}
const cfZoneId = grab('Validate Input', j => j.cfZoneId);
const projectId = grab('Create Plasmic Project', j => j.projectId);
const appUuid = grab('Create Coolify App', j => j.uuid);
const dnsId = grab('Create DNS Record', j => (j && j.result) ? j.result.id : null);
return [{ json: { stage, cause, projectId, appUuid, dnsId, cfZoneId, diag } }];

const r = $input.first().json;
const raw = String(r.stdout ?? '').trim();
const nl = raw.lastIndexOf('\n');
const status = Number(nl === -1 ? raw : raw.slice(nl + 1));
const text = nl === -1 ? '' : raw.slice(0, nl).trim();
let body = null;
try { body = JSON.parse(text); } catch (e) {}
if (!Number.isFinite(status) || status >= 400 || !body || body.ok !== true) {
  const cause = (body && (body.error || body.message)) || text.slice(0, 300) || String(r.stderr || '').slice(0, 200) || 'no response';
  throw new Error('page-api create-project failed (HTTP ' + status + '): ' + cause);
}
return [{ json: body }];

